import React, { useState } from "react"; import { Card, CardContent } from "@/components/ui/card"; import { Button } from "@/components/ui/button"; import { Input } from "@/components/ui/input"; import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"; import { motion } from "framer-motion";

export default function MCCSystem() { const sharePrice = 0.5;

// AUTH SYSTEM const [role, setRole] = useState("superadmin"); // superadmin | admin | member

// CORE STATES const [members, setMembers] = useState([]); const [projects, setProjects] = useState([]); const [votes, setVotes] = useState([]); const [name, setName] = useState(""); const [shares, setShares] = useState(1); const [profit, setProfit] = useState(0);

// WALLET SYSTEM const addMember = () => { const investment = shares * sharePrice; const newMember = { id: Date.now(), name, shares, investment, wallet: 0, dividend: 0, transactions: [ { type: "investment", amount: investment, date: new Date().toLocaleDateString() } ] }; setMembers([...members, newMember]); setName(""); setShares(1); };

// PROFIT DISTRIBUTION const distributeProfit = () => { const dividendPool = profit * 0.4; const totalShares = members.reduce((acc, m) => acc + m.shares, 0);

const updated = members.map((m) => {
  const dividend = totalShares > 0 ? (m.shares / totalShares) * dividendPool : 0;
  return {
    ...m,
    dividend,
    wallet: m.wallet + dividend,
    transactions: [
      ...m.transactions,
      { type: "dividend", amount: dividend, date: new Date().toLocaleDateString() }
    ]
  };
});

setMembers(updated);

};

// VOTING SYSTEM const createVote = (title) => { setVotes([...votes, { id: Date.now(), title, yes: 0, no: 0 }]); };

const castVote = (id, type) => { setVotes(votes.map(v => v.id === id ? { ...v, [type]: v[type] + 1 } : v)); };

// PDF REPORT (SIMULATION) const generateReport = () => { alert("Financial Report Generated (PDF Integration Ready)"); };

const totalCapital = members.reduce((acc, m) => acc + m.investment, 0);

return ( <div className="min-h-screen bg-gray-100 p-6"> <motion.h1 initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-3xl font-bold mb-6"> MCC Enterprise Cooperative System </motion.h1>

<Tabs defaultValue="dashboard">
    <TabsList className="grid grid-cols-4 mb-6">
      <TabsTrigger value="dashboard">Dashboard</TabsTrigger>
      <TabsTrigger value="members">Members</TabsTrigger>
      <TabsTrigger value="voting">Voting</TabsTrigger>
      <TabsTrigger value="reports">Reports</TabsTrigger>
    </TabsList>

    {/* DASHBOARD */}
    <TabsContent value="dashboard">
      <div className="grid md:grid-cols-3 gap-6">
        <Card className="rounded-2xl shadow-md">
          <CardContent className="p-4">
            <h2>Total Members</h2>
            <p className="text-2xl font-bold">{members.length}</p>
          </CardContent>
        </Card>
        <Card className="rounded-2xl shadow-md">
          <CardContent className="p-4">
            <h2>Total Capital</h2>
            <p className="text-2xl font-bold">${totalCapital.toFixed(2)}</p>
          </CardContent>
        </Card>
        <Card className="rounded-2xl shadow-md">
          <CardContent className="p-4">
            <Input type="number" placeholder="Set Profit" value={profit} onChange={(e)=>setProfit(Number(e.target.value))}/>
            <Button onClick={distributeProfit} className="mt-2 w-full">Distribute 40%</Button>
          </CardContent>
        </Card>
      </div>
    </TabsContent>

    {/* MEMBERS */}
    <TabsContent value="members">
      <Card className="rounded-2xl shadow-md mb-6">
        <CardContent className="p-4 grid md:grid-cols-4 gap-4">
          <Input placeholder="Member Name" value={name} onChange={(e)=>setName(e.target.value)} />
          <Input type="number" min="1" value={shares} onChange={(e)=>setShares(Number(e.target.value))}/>
          <Button onClick={addMember}>Add Member</Button>
        </CardContent>
      </Card>

      {members.map(member => (
        <Card key={member.id} className="rounded-2xl shadow-sm mb-4">
          <CardContent className="p-4">
            <h3 className="font-bold">{member.name}</h3>
            <p>Shares: {member.shares}</p>
            <p>Wallet: ${member.wallet.toFixed(2)}</p>
            <p className="text-green-600">Dividend: ${member.dividend.toFixed(2)}</p>
          </CardContent>
        </Card>
      ))}
    </TabsContent>

    {/* VOTING */}
    <TabsContent value="voting">
      <Button onClick={()=>createVote("New Investment Project")}>Create Vote</Button>
      {votes.map(v => (
        <Card key={v.id} className="rounded-2xl shadow-md mt-4">
          <CardContent className="p-4">
            <h3 className="font-bold">{v.title}</h3>
            <p>Yes: {v.yes} | No: {v.no}</p>
            <Button onClick={()=>castVote(v.id, "yes")} className="mr-2">Vote Yes</Button>
            <Button onClick={()=>castVote(v.id, "no")}>Vote No</Button>
          </CardContent>
        </Card>
      ))}
    </TabsContent>

    {/* REPORTS */}
    <TabsContent value="reports">
      <Button onClick={generateReport}>Generate Financial PDF Report</Button>
    </TabsContent>
  </Tabs>
</div>

); }


